14	library ieee;
15	use ieee.std_logic_1164.all;
16	use ieee.numeric_std.all;
17	
18	
19	package axi_lite_pkg is
20	
21	  ------------------------------------------------------------------------------
22	  -- A (Address Read and Address Write) channels
23	  ------------------------------------------------------------------------------
24	
25	  -- Address field (ARADDR or AWADDR).
26	  -- The width value below is a max value, implementation should only take into regard the bits
27	  -- that are actually used.
28	  subtype axi_lite_address_width_t is positive range 1 to 64;
29	
30	  -- Record for the AR/AW signals in the master-to-slave direction.
31	  type axi_lite_m2s_a_t is record
32	    valid : std_ulogic;
33	    addr : u_unsigned(axi_lite_address_width_t'high - 1 downto 0);
34	    -- Excluded members: prot
35	    -- These are typically not changed on a transfer-to-transfer basis.
36	  end record;
37	
38	  constant axi_lite_m2s_a_init : axi_lite_m2s_a_t := (valid => '0', addr => (others => '0'));
39	  function axi_lite_m2s_a_sz(addr_width : axi_lite_address_width_t) return positive;
40	
41	  -- Record for the AR/AW signals in the slave-to-master direction.
42	  type axi_lite_s2m_a_t is record
43	    ready : std_ulogic;
44	  end record;
45	
46	  constant axi_lite_s2m_a_init : axi_lite_s2m_a_t := (ready => '0');
47	
48	
49	  ------------------------------------------------------------------------------
50	  -- W (Write Data) channels
51	  ------------------------------------------------------------------------------
52	
53	  -- Data field (RDATA or WDATA).
54	  -- The width value below is a max value, implementation should only take into regard the bits
55	  -- that are actually used.
56	  constant axi_lite_data_sz : positive := 64;
57	  subtype axi_lite_data_width_t is positive range 8 to axi_lite_data_sz;
58	
59	  -- Check that a provided data width is valid to be used with AXI-Lite.
60	  -- Return 'true' if everything is okay, otherwise 'false'.
61	  function sanity_check_axi_lite_data_width(data_width : integer) return boolean;
62	
63	  -- Write data strobe field (WSTRB).
64	  -- The width value below is a max value, implementation should only take into regard the bits
65	  -- that are actually used.
66	  constant axi_lite_w_strb_sz : positive := axi_lite_data_sz / 8;
67	
68	  function to_axi_lite_strb(
69	    data_width : axi_lite_data_width_t
70	  ) return std_ulogic_vector;
71	
72	  -- Record for the W signals in the master-to-slave direction.
73	  type axi_lite_m2s_w_t is record
74	    valid : std_ulogic;
75	    data : std_ulogic_vector(axi_lite_data_sz - 1 downto 0);
76	    strb : std_ulogic_vector(axi_lite_w_strb_sz - 1 downto 0);
77	  end record;
78	
79	  constant axi_lite_m2s_w_init : axi_lite_m2s_w_t := (
80	    valid => '0', data => (others => '-'), strb => (others => '0')
81	  );
82	  function axi_lite_m2s_w_sz(data_width : axi_lite_data_width_t) return positive;
83	
84	  function to_slv(
85	    data : axi_lite_m2s_w_t; data_width : axi_lite_data_width_t
86	  ) return std_ulogic_vector;
87	  function to_axi_lite_m2s_w(
88	    data : std_ulogic_vector; data_width : axi_lite_data_width_t
89	  ) return axi_lite_m2s_w_t;
90	
91	  -- Record for the W signals in the slave-to-master direction.
92	  type axi_lite_s2m_w_t is record
93	    ready : std_ulogic;
94	  end record;
95	
96	  constant axi_lite_s2m_w_init : axi_lite_s2m_w_t := (ready => '0');
97	
98	
99	  ------------------------------------------------------------------------------
100	  -- B (Write Response) channels
101	  ------------------------------------------------------------------------------
102	
103	  -- Record for the B signals in the master-to-slave direction.
104	  type axi_lite_m2s_b_t is record
105	    ready : std_ulogic;
106	  end record;
107	
108	  constant axi_lite_m2s_b_init : axi_lite_m2s_b_t := (ready => '0');
109	
110	  -- Response field (RRESP or BRESP).
111	  constant axi_resp_sz : positive := 2;
112	  subtype axi_lite_resp_t is std_ulogic_vector(axi_resp_sz - 1 downto 0);
113	
114	  constant axi_lite_resp_okay : axi_lite_resp_t := "00";
115	  constant axi_lite_resp_exokay : axi_lite_resp_t := "01";
116	  constant axi_lite_resp_slverr : axi_lite_resp_t := "10";
117	  constant axi_lite_resp_decerr : axi_lite_resp_t := "11";
118	
119	  -- Record for the B signals in the slave-to-master direction.
120	  type axi_lite_s2m_b_t is record
121	    valid : std_ulogic;
122	    resp : axi_lite_resp_t;
123	  end record;
124	
125	  constant axi_lite_s2m_b_init : axi_lite_s2m_b_t := (valid => '0', resp => (others => '-'));
126	  -- Excluded member: valid
127	  constant axi_lite_s2m_b_sz : positive := axi_resp_sz;
128	
129	
130	  ------------------------------------------------------------------------------
131	  -- R (Read Data) channels
132	  ------------------------------------------------------------------------------
133	
134	  -- Record for the R signals in the master-to-slave direction.
135	  type axi_lite_m2s_r_t is record
136	    ready : std_ulogic;
137	  end record;
138	
139	  constant axi_lite_m2s_r_init : axi_lite_m2s_r_t := (ready => '0');
140	
141	  -- Record for the R signals in the slave-to-master direction.
142	  type axi_lite_s2m_r_t is record
143	    valid : std_ulogic;
144	    data : std_ulogic_vector(axi_lite_data_sz - 1 downto 0);
145	    resp : axi_lite_resp_t;
146	  end record;
147	
148	  constant axi_lite_s2m_r_init : axi_lite_s2m_r_t := (
149	    valid => '0', data => (others => '-'), resp => (others => '-')
150	  );
151	  function axi_lite_s2m_r_sz(data_width : axi_lite_data_width_t) return positive;
152	
153	  function to_slv(
154	    data : axi_lite_s2m_r_t; data_width : axi_lite_data_width_t
155	  ) return std_ulogic_vector;
156	  function to_axi_lite_s2m_r(
157	    data : std_ulogic_vector; data_width : axi_lite_data_width_t
158	  ) return axi_lite_s2m_r_t;
159	
160	
161	  ------------------------------------------------------------------------------
162	  -- The complete buses
163	  ------------------------------------------------------------------------------
164	
165	  type axi_lite_read_m2s_t is record
166	    ar : axi_lite_m2s_a_t;
167	    r : axi_lite_m2s_r_t;
168	  end record;
169	  type axi_lite_read_m2s_vec_t is array (integer range <>) of axi_lite_read_m2s_t;
170	
171	  constant axi_lite_read_m2s_init : axi_lite_read_m2s_t := (
172	    ar => axi_lite_m2s_a_init,
173	    r => axi_lite_m2s_r_init
174	  );
175	
176	  type axi_lite_read_s2m_t is record
177	    ar : axi_lite_s2m_a_t;
178	    r : axi_lite_s2m_r_t;
179	  end record;
180	  type axi_lite_read_s2m_vec_t is array (integer range <>) of axi_lite_read_s2m_t;
181	
182	  constant axi_lite_read_s2m_init : axi_lite_read_s2m_t := (
183	    ar => axi_lite_s2m_a_init,
184	    r => axi_lite_s2m_r_init
185	  );
186	
187	  type axi_lite_write_m2s_t is record
188	    aw : axi_lite_m2s_a_t;
189	    w : axi_lite_m2s_w_t;
190	    b : axi_lite_m2s_b_t;
191	  end record;
192	  type axi_lite_write_m2s_vec_t is array (integer range <>) of axi_lite_write_m2s_t;
193	
194	  constant axi_lite_write_m2s_init : axi_lite_write_m2s_t := (
195	    aw => axi_lite_m2s_a_init,
196	    w => axi_lite_m2s_w_init,
197	    b => axi_lite_m2s_b_init
198	  );
199	
200	  type axi_lite_write_s2m_t is record
201	    aw : axi_lite_s2m_a_t;
202	    w : axi_lite_s2m_w_t;
203	    b : axi_lite_s2m_b_t;
204	  end record;
205	  type axi_lite_write_s2m_vec_t is array (integer range <>) of axi_lite_write_s2m_t;
206	
207	  constant axi_lite_write_s2m_init : axi_lite_write_s2m_t := (
208	    aw => axi_lite_s2m_a_init,
209	    w => axi_lite_s2m_w_init,
210	    b => axi_lite_s2m_b_init
211	  );
212	
213	  type axi_lite_m2s_t is record
214	    read : axi_lite_read_m2s_t;
215	    write : axi_lite_write_m2s_t;
216	  end record;
217	  type axi_lite_m2s_vec_t is array (integer range <>) of axi_lite_m2s_t;
218	
219	  constant axi_lite_m2s_init : axi_lite_m2s_t := (
220	    read => axi_lite_read_m2s_init,
221	    write => axi_lite_write_m2s_init
222	  );
223	
224	  type axi_lite_s2m_t is record
225	    read : axi_lite_read_s2m_t;
226	    write : axi_lite_write_s2m_t;
227	  end record;
228	  type axi_lite_s2m_vec_t is array (integer range <>) of axi_lite_s2m_t;
229	
230	  constant axi_lite_s2m_init : axi_lite_s2m_t := (
231	    read => axi_lite_read_s2m_init,
232	    write => axi_lite_write_s2m_init
233	  );
234	
235	end;
236	
237	package body axi_lite_pkg is
238	
239	  ------------------------------------------------------------------------------
240	  function axi_lite_m2s_a_sz(addr_width : axi_lite_address_width_t) return positive is
241	  begin
242	    -- Excluded member: valid.
243	    return addr_width;
244	  end function;
245	  ------------------------------------------------------------------------------
246	
247	  ------------------------------------------------------------------------------
248	  function sanity_check_axi_lite_data_width(data_width : integer) return boolean is
249	    constant message : string := ". Got data_width=" & integer'image(data_width) & ".";
250	  begin
251	    if data_width /= 32 and data_width /= 64 then
252	      report "AXI-Lite data width must be either 32 or 64" & message;
253	      return false;
254	    end if;
255	
256	    return true;
257	  end function;
258	
259	  function to_axi_lite_strb(
260	    data_width : axi_lite_data_width_t
261	  ) return std_ulogic_vector is
262	    variable result : std_ulogic_vector(axi_lite_w_strb_sz - 1 downto 0) := (others => '0');
263	  begin
264	    assert sanity_check_axi_lite_data_width(data_width)
265	      report "Invalid data width, see printout above."
266	      severity failure;
267	
268	    result(data_width / 8 - 1 downto 0) := (others => '1');
269	
270	    return result;
271	  end function;
272	
273	  function axi_w_strb_width(data_width : axi_lite_data_width_t) return positive is
274	  begin
275	    assert sanity_check_axi_lite_data_width(data_width)
276	      report "Invalid data width, see printout above."
277	      severity failure;
278	
279	    return data_width / 8;
280	  end function;
281	
282	  function axi_lite_m2s_w_sz(data_width : axi_lite_data_width_t) return positive is
283	  begin
284	    assert sanity_check_axi_lite_data_width(data_width)
285	      report "Invalid data width, see printout above."
286	      severity failure;
287	
288	    -- Excluded member: valid
289	    return data_width + axi_w_strb_width(data_width);
290	  end function;
291	
292	  function to_slv(
293	    data : axi_lite_m2s_w_t; data_width : axi_lite_data_width_t
294	  ) return std_ulogic_vector is
295	    variable result : std_ulogic_vector(axi_lite_m2s_w_sz(data_width) - 1 downto 0);
296	    variable lo, hi : natural := 0;
297	  begin
298	    lo := 0;
299	    hi := lo + data_width - 1;
300	    result(hi downto lo) := data.data(data_width - 1 downto 0);
301	
302	    lo := hi + 1;
303	    hi := lo + axi_w_strb_width(data_width) - 1;
304	    result(hi downto lo) := data.strb(axi_w_strb_width(data_width) - 1 downto 0);
305	
306	    assert hi = result'high;
307	
308	    return result;
309	  end function;
310	
311	  function to_axi_lite_m2s_w(
312	    data : std_ulogic_vector; data_width : axi_lite_data_width_t
313	  ) return axi_lite_m2s_w_t is
314	    variable result : axi_lite_m2s_w_t := axi_lite_m2s_w_init;
315	    variable lo, hi : natural := 0;
316	  begin
317	    lo := 0;
318	    hi := lo + data_width - 1;
319	    result.data(data_width - 1 downto 0) := data(hi downto lo);
320	
321	    lo := hi + 1;
322	    hi := lo + axi_w_strb_width(data_width) - 1;
323	    result.strb(axi_w_strb_width(data_width) - 1 downto 0) := data(hi downto lo);
324	
325	    assert hi = data'high;
326	
327	    return result;
328	  end function;
329	  ------------------------------------------------------------------------------
330	
331	  ------------------------------------------------------------------------------
332	  function axi_lite_s2m_r_sz(data_width : axi_lite_data_width_t)  return positive is
333	  begin
334	    assert sanity_check_axi_lite_data_width(data_width)
335	      report "Invalid data width, see printout above."
336	      severity failure;
337	
338	    -- Excluded member: valid
339	    return data_width + axi_resp_sz;
340	  end function;
341	
342	  function to_slv(
343	    data : axi_lite_s2m_r_t; data_width : axi_lite_data_width_t
344	  ) return std_ulogic_vector is
345	    variable result : std_ulogic_vector(axi_lite_s2m_r_sz(data_width) - 1 downto 0);
346	    variable lo, hi : natural := 0;
347	  begin
348	    lo := 0;
349	    hi := lo + data_width - 1;
350	    result(hi downto lo) := data.data(data_width - 1 downto 0);
351	
352	    lo := hi + 1;
353	    hi := lo + axi_resp_sz - 1;
354	    result(hi downto lo) := data.resp;
355	
356	    assert hi = result'high;
357	
358	    return result;
359	  end function;
360	
361	  function to_axi_lite_s2m_r(
362	    data : std_ulogic_vector; data_width : axi_lite_data_width_t
363	  ) return axi_lite_s2m_r_t is
364	    variable result : axi_lite_s2m_r_t := axi_lite_s2m_r_init;
365	    variable lo, hi : natural := 0;
366	  begin
367	    lo := 0;
368	    hi := lo + data_width - 1;
369	    result.data(data_width - 1 downto 0) := data(hi downto lo);
370	
371	    lo := hi + 1;
372	    hi := lo + axi_resp_sz - 1;
373	    result.resp := data(hi downto lo);
374	
375	    assert hi = data'high;
376	
377	    return result;
378	  end function;
379	  ------------------------------------------------------------------------------
380	
381	end;
